package com.datamaster.module.assets.controller.admin.discovery;import cn.hutool.core.date.DateUtil;import io.swagger.v3.oas.annotations.Operation;import io.swagger.v3.oas.annotations.tags.Tag;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.validation.annotation.Validated;import org.springframework.web.bind.annotation.*;import org.springframework.web.multipart.MultipartFile;import com.datamaster.common.annotation.Log;import com.datamaster.common.core.controller.BaseController;import com.datamaster.common.core.domain.AjaxResult;import com.datamaster.common.core.domain.CommonResult;import com.datamaster.common.core.page.PageParam;import com.datamaster.common.core.page.PageResult;import com.datamaster.common.enums.BusinessType;import com.datamaster.common.utils.object.BeanUtils;import com.datamaster.common.utils.poi.ExcelUtil;import com.datamaster.module.assets.controller.admin.discovery.vo.AssetsDiscoveryColumnPageReqVO;import com.datamaster.module.assets.controller.admin.discovery.vo.AssetsDiscoveryColumnRespVO;import com.datamaster.module.assets.controller.admin.discovery.vo.AssetsDiscoveryColumnSaveReqVO;import com.datamaster.module.assets.convert.discovery.AssetsDiscoveryColumnConvert;import com.datamaster.module.assets.dal.dataobject.discovery.AssetsDiscoveryColumnDO;import com.datamaster.module.assets.service.discovery.IAssetsDiscoveryColumnService;import javax.annotation.Resource;import javax.servlet.http.HttpServletResponse;import javax.validation.Valid;import java.util.Arrays;import java.util.List;/** * 数据发现字段Controller * * @author DATAMASTER * @date 2025-02-11 */@Tag(name = "数据发现字段")@RestController@RequestMapping("/ast/discoveryColumn")@Validated
public class AssetsDiscoveryColumnController extends BaseController {    @Resource    private IAssetsDiscoveryColumnService AssetsDiscoveryColumnService;    @Operation(summary = "查询数据发现字段列表")    @PreAuthorize("@ss.hasPermi('da:discoveryColumn:list')")    @GetMapping("/list")    public CommonResult<PageResult<AssetsDiscoveryColumnRespVO>> list(AssetsDiscoveryColumnPageReqVO AssetsDiscoveryColumn) {        PageResult<AssetsDiscoveryColumnDO> page = AssetsDiscoveryColumnService.getDaDiscoveryColumnPage(AssetsDiscoveryColumn);        return CommonResult.success(BeanUtils.toBean(page, AssetsDiscoveryColumnRespVO.class));    }    @Operation(summary = "查询数据发现字段列表")    @PreAuthorize("@ss.hasPermi('da:discoveryColumn:list')")    @GetMapping("/getDaDiscoveryColumnList")    public CommonResult<List<AssetsDiscoveryColumnRespVO>> getDaDiscoveryColumnList(AssetsDiscoveryColumnPageReqVO AssetsDiscoveryColumn) {        List<AssetsDiscoveryColumnDO> AssetsDiscoveryColumnList = AssetsDiscoveryColumnService.getDaDiscoveryColumnList(AssetsDiscoveryColumn);        List<AssetsDiscoveryColumnRespVO> bean = BeanUtils.toBean(AssetsDiscoveryColumnList, AssetsDiscoveryColumnRespVO.class);        return CommonResult.success(bean);    }    @Operation(summary = "导出数据发现字段列表")    @PreAuthorize("@ss.hasPermi('da:discoveryColumn:export')")    @Log(title = "数据发现字段", businessType = BusinessType.EXPORT)    @PostMapping("/export")    public void export(HttpServletResponse response, AssetsDiscoveryColumnPageReqVO exportReqVO) {        exportReqVO.setPageSize(PageParam.PAGE_SIZE_NONE);        List<AssetsDiscoveryColumnDO> list = (List<AssetsDiscoveryColumnDO>) AssetsDiscoveryColumnService.getDaDiscoveryColumnPage(exportReqVO).getRows();        ExcelUtil<AssetsDiscoveryColumnRespVO> util = new ExcelUtil<>(AssetsDiscoveryColumnRespVO.class);        util.exportExcel(response, AssetsDiscoveryColumnConvert.INSTANCE.convertToRespVOList(list), "应用管理数据");    }    @Operation(summary = "导入数据发现字段列表")    @PreAuthorize("@ss.hasPermi('da:discoveryColumn:import')")    @Log(title = "数据发现字段", businessType = BusinessType.IMPORT)    @PostMapping("/importData")    public AjaxResult importData(MultipartFile file, boolean updateSupport) throws Exception {        ExcelUtil<AssetsDiscoveryColumnRespVO> util = new ExcelUtil<>(AssetsDiscoveryColumnRespVO.class);        List<AssetsDiscoveryColumnRespVO> importExcelList = util.importExcel(file.getInputStream());        String operName = getUsername();        String message = AssetsDiscoveryColumnService.importDaDiscoveryColumn(importExcelList, updateSupport, operName);        return success(message);    }    @Operation(summary = "获取数据发现字段详细信息")    @PreAuthorize("@ss.hasPermi('da:discoveryColumn:query')")    @GetMapping(value = "/{id}")    public CommonResult<AssetsDiscoveryColumnRespVO> getInfo(@PathVariable("id") Long id) {        AssetsDiscoveryColumnDO AssetsDiscoveryColumnDO = AssetsDiscoveryColumnService.getDaDiscoveryColumnById(id);        return CommonResult.success(BeanUtils.toBean(AssetsDiscoveryColumnDO, AssetsDiscoveryColumnRespVO.class));    }    @Operation(summary = "新增数据发现字段")    @PreAuthorize("@ss.hasPermi('da:discoveryColumn:add')")    @Log(title = "数据发现字段", businessType = BusinessType.INSERT)    @PostMapping    public CommonResult<Long> add(@Valid @RequestBody AssetsDiscoveryColumnSaveReqVO AssetsDiscoveryColumn) {        AssetsDiscoveryColumn.setCreatorId(getUserId());        AssetsDiscoveryColumn.setCreateBy(getNickName());        AssetsDiscoveryColumn.setCreateTime(DateUtil.date());        return CommonResult.toAjax(AssetsDiscoveryColumnService.createDaDiscoveryColumn(AssetsDiscoveryColumn));    }    @Operation(summary = "修改数据发现字段")    @PreAuthorize("@ss.hasPermi('da:discoveryColumn:edit')")    @Log(title = "数据发现字段", businessType = BusinessType.UPDATE)    @PutMapping    public CommonResult<Integer> edit(@Valid @RequestBody AssetsDiscoveryColumnSaveReqVO AssetsDiscoveryColumn) {        AssetsDiscoveryColumn.setUpdatorId(getUserId());        AssetsDiscoveryColumn.setUpdateBy(getNickName());        AssetsDiscoveryColumn.setUpdateTime(DateUtil.date());        return CommonResult.toAjax(AssetsDiscoveryColumnService.updateDaDiscoveryColumn(AssetsDiscoveryColumn));    }    @Operation(summary = "删除数据发现字段")    @PreAuthorize("@ss.hasPermi('da:discoveryColumn:remove')")    @Log(title = "数据发现字段", businessType = BusinessType.DELETE)    @DeleteMapping("/{ids}")    public CommonResult<Integer> remove(@PathVariable Long[] ids) {        return CommonResult.toAjax(AssetsDiscoveryColumnService.removeDaDiscoveryColumn(Arrays.asList(ids)));    }}